void insertThreaded(struct Node** root, int key) {
    struct Node* newnode = (struct Node*)malloc(sizeof(struct Node));
    newnode->data = key;
    newnode->lthread = 1;  // Will be a thread initially
    newnode->rthread = 1;  // Will be a thread initially

    // Case 1: Tree is empty
    if (*root == NULL) {
        *root = newnode;
        newnode->left = NULL;
        newnode->right = NULL;
        return;
    }

    // Case 2: Find position and insert
    struct Node* parent = NULL;
    struct Node* current = *root;

    while (current != NULL) {
        parent = current;
        if (key < current->data) {
            if (current->lthread == 0)  // Has left child
                current = current->left;
            else  // Found position
                break;
        } else {
            if (current->rthread == 0)  // Has right child
                current = current->right;
            else  // Found position
                break;
        }
    }

    // Insert as left or right child
    if (key < parent->data) {
        newnode->left = parent->left;
        newnode->right = parent;
        parent->left = newnode;
        parent->lthread = 0;
    } else {
        newnode->left = parent;
        newnode->right = parent->right;
        parent->right = newnode;
        parent->rthread = 0;
    }
}
